# MongoDB-style operations using dict-based storage
class SimpleDocStore:
    def __init__(self):
        self.collections = {}
    def __getitem__(self, name):
        if name not in self.collections:
            self.collections[name] = []
        return self.collections[name]

db = SimpleDocStore()
db['users'].append({'name': 'Alice', 'age': 30})
db['users'].append({'name': 'Bob', 'age': 25})
print(f'Documents: {db["users"]}')
print(f'Filter age > 27: {[u for u in db["users"] if u["age"] > 27]}')

