# Redis-style key-value operations using dict
class SimpleKVStore:
    def __init__(self):
        self.store = {}
    def set(self, key, value, ex=None):
        self.store[key] = value
    def get(self, key):
        return self.store.get(key)
    def delete(self, key):
        return self.store.pop(key, None)
    def keys(self):
        return list(self.store.keys())

r = SimpleKVStore()
r.set('user:1', 'Alice')
r.set('user:2', 'Bob')
r.set('counter', '42')
print(f'user:1 = {r.get("user:1")}')
print(f'Keys: {r.keys()}')
r.delete('user:2')
print(f'After delete: {r.keys()}')
